// Re-running with the same IDEMPOTENCY_KEY env value is safe: Autumn
// will deduplicate the event and only record usage once.
const idempotencyKey = process.env.IDEMPOTENCY_KEY ?? randomUUID();

console.log(`Using idempotency key: ${idempotencyKey}`);

const autumn = new Autumn({
  secretKey: process.env.AUTUMN_SECRET_KEY,
});

const result = await autumn.track(
  {
    customerId: "user_test_001",
    featureId: "api-calls",
    value: 1,
  },
  {
    // Pass the idempotency key as a standard HTTP header so Autumn can
    // detect duplicate requests and prevent double-billing on retries.
    headers: {
      "Idempotency-Key": idempotencyKey,
    },
  }
);

const output = {
  idempotencyKey,
  result,
};

